"use strict";(self.webpackChunkmy_website=self.webpackChunkmy_website||[]).push([[7702],{7696:(e,n,t)=>{t.r(n),t.d(n,{assets:()=>l,contentTitle:()=>s,default:()=>p,frontMatter:()=>o,metadata:()=>u,toc:()=>a});var r=t(4848),i=t(8453);const o={},s=void 0,u={id:"Heap/Top K frequent elements",title:"Top K frequent elements",description:"",source:"@site/neetcode150/Heap/Top K frequent elements.md",sourceDirName:"Heap",slug:"/Heap/Top K frequent elements",permalink:"/leetcode/neetcode150/Heap/Top K frequent elements",draft:!1,unlisted:!1,tags:[],version:"current",frontMatter:{},sidebar:"tutorialSidebar",previous:{title:"Task Scheduler",permalink:"/leetcode/neetcode150/Heap/Task Scheduler"},next:{title:"Insert Interval",permalink:"/leetcode/neetcode150/Intervals/Insert Interval"}},l={},a=[];function c(e){const n={code:"code",pre:"pre",...(0,i.R)(),...e.components};return(0,r.jsxs)(r.Fragment,{children:[(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{className:"language-python",children:'from collections import Counter\r\nclass Solution:\r\n    def topKFrequent(self, nums: List[int], k: int) -> List[int]:\r\n        count = Counter(nums)\r\n        unique = list(count.keys())\r\n        \r\n        def partition(left, right, pivot) -> int:\r\n            pivot_frequency = count[unique[pivot]]\r\n            # 1. Move the pivot to end\r\n            unique[pivot], unique[right] = unique[right], unique[pivot]  \r\n            \r\n            # 2. Move all less frequent elements to the left\r\n            store_index = left\r\n            for i in range(left, right):\r\n                if count[unique[i]] < pivot_frequency:\r\n                    unique[store_index], unique[i] = unique[i], unique[store_index]\r\n                    store_index += 1\r\n\r\n            # 3. Move the pivot to its final place\r\n            unique[right], unique[store_index] = unique[store_index], unique[right]  \r\n            \r\n            return store_index\r\n        \r\n        def quickselect(left, right, k_smallest) -> None:\r\n            """\r\n            Sort a list within left..right till kth less frequent element\r\n            takes its place. \r\n            """\r\n            # base case: the list contains only one element\r\n            if left == right: \r\n                return\r\n            \r\n            # Select a random pivot_index\r\n            pivot = random.randint(left, right)     \r\n                            \r\n            # Find the pivot position in a sorted list   \r\n            pivot_index = partition(left, right, pivot)\r\n            \r\n            # If the pivot is in its final sorted position\r\n            if k_smallest == pivot_index:\r\n                 return \r\n            # go left\r\n            elif k_smallest < pivot_index:\r\n                quickselect(left, pivot_index - 1, k_smallest)\r\n            # go right\r\n            else:\r\n                quickselect(pivot_index + 1, right, k_smallest)\r\n         \r\n        n = len(unique) \r\n        # kth top frequent element is (n - k)th less frequent.\r\n        # Do a partial sort: from less frequent to the most frequent, till\r\n        # (n - k)th less frequent element takes its place (n - k) in a sorted array. \r\n        # All elements on the left are less frequent.\r\n        # All the elements on the right are more frequent.  \r\n        quickselect(0, n - 1, n - k)\r\n        # Return top k frequent elements\r\n        return unique[(n - k):]\r\n# Time Complexity: O()\r\n# Space Complexity: O()\n'})}),"\n",(0,r.jsx)(n.pre,{children:(0,r.jsx)(n.code,{className:"language-java",children:"class Solution {\r\n    public int[] topKFrequent(int[] nums, int k) {\r\n        Map<Integer, Integer> count = new HashMap<>();\r\n        for (int num : nums) {\r\n            count.put(num, count.getOrDefault(num, 0) + 1);\r\n        }\r\n        Queue<Integer> heap = new PriorityQueue<>(\r\n            (n1, n2) -> count.get(n1) - count.get(n2)\r\n        );\r\n\r\n        for (int n : count.keySet()) {\r\n            heap.add(n);\r\n            if (heap.size() > k) {\r\n                heap.poll();\r\n            }\r\n        }\r\n\r\n        int[] ans = new int[k];\r\n        for (int i = k-1; i >=0; i--) {\r\n            ans[i] = heap.poll();\r\n        }\r\n\r\n        return ans;\r\n    }\r\n}\n"})})]})}function p(e={}){const{wrapper:n}={...(0,i.R)(),...e.components};return n?(0,r.jsx)(n,{...e,children:(0,r.jsx)(c,{...e})}):c(e)}},8453:(e,n,t)=>{t.d(n,{R:()=>s,x:()=>u});var r=t(6540);const i={},o=r.createContext(i);function s(e){const n=r.useContext(o);return r.useMemo((function(){return"function"==typeof e?e(n):{...n,...e}}),[n,e])}function u(e){let n;return n=e.disableParentContext?"function"==typeof e.components?e.components(i):e.components||i:s(e.components),r.createElement(o.Provider,{value:n},e.children)}}}]);